input.script:
export const meta = {
  name: 'helldeck-playtest-r1',
  description: 'Simulated playtests + adversarial attacks on HELLDECK 2.0 spec v1',
  phases: [
    { title: 'Playtest', detail: '6 simulated friend groups play a full Night' },
    { title: 'Attack', detail: '4 adversarial specialists try to break the model' },
  ],
}

const SPEC = '/private/tmp/claude-501/-Users-nicholastoledo-Development-active-HELLDECK/4eb51e65-3e38-49e9-b745-6d128c919d2d/scratchpad/spec_v1.md'
const SCRATCH = '/private/tmp/claude-501/-Users-nicholastoledo-Development-active-HELLDECK/4eb51e65-3e38-49e9-b745-6d128c919d2d/scratchpad'

const PLAYTEST_SCHEMA = {
  type: 'object',
  properties: {
    group_verdict: { type: 'string', enum: ['FUN', 'MIXED', 'NOT_FUN'] },
    fun_score_1_10: { type: 'number' },
    laughs_per_round_estimate: { type: 'number' },
    best_moments: { type: 'array', items: { type: 'string' } },
    failures: { type: 'array', items: { type: 'object', properties: {
      where: { type: 'string' }, what: { type: 'string' },
      severity: { type: 'string', enum: ['FATAL', 'MAJOR', 'MINOR'] },
      fix: { type: 'string' } }, required: ['where', 'what', 'severity', 'fix'] } },
    per_game: { type: 'array', items: { type: 'object', properties: {
      game: { type: 'string' }, verdict: { type: 'string', enum: ['LANDED', 'OK', 'DIED'] },
      note: { type: 'string' } }, required: ['game', 'verdict', 'note'] } },
    would_play_again: { type: 'boolean' },
    would_someone_pay_to_host: { type: 'boolean' },
    narrative_highlights: { type: 'string', description: 'max 400 words of the most instructive simulation beats' },
  },
  required: ['group_verdict', 'fun_score_1_10', 'failures', 'per_game', 'would_play_again', 'would_someone_pay_to_host', 'narrative_highlights'],
}

const ATTACK_SCHEMA = {
  type: 'object',
  properties: {
    verdict: { type: 'string', enum: ['HOLDS', 'HOLDS_WITH_FIXES', 'BREAKS'] },
    kill_shots: { type: 'array', items: { type: 'object', properties: {
      claim: { type: 'string' }, severity: { type: 'string', enum: ['FATAL', 'MAJOR', 'MINOR'] },
      evidence: { type: 'string' }, fix: { type: 'string' } }, required: ['claim', 'severity', 'evidence', 'fix'] } },
    summary: { type: 'string', description: 'max 300 words' },
  },
  required: ['verdict', 'kill_shots', 'summary'],
}

const COMMON = `Read the game design spec at ${SPEC} first (the Read tool). It is a redesign of HELLDECK, a party game for friend groups: every player on their own phone, same room, no TV; host has a native Android app, joiners use their mobile browser. Supporting research reports live in ${SCRATCH}/report_*.md — read any you need (especially report_read_rules-interactions.md for full game rules and report_research_design-theory.md for design principles). Game identity: UNHINGED, never WHOLESOME — a roast where everyone's in on it. Your job is NOT to be nice. A false 'it's fun' costs months of wasted build; a found flaw costs nothing.`

const groups = [
  { label: 'playtest:roommates4', desc: `4 college roommates (Maya, Jules, Dex, Sam) pregaming in a tiny apartment before going out. Very online, 2 of them already drunk, short fuses for anything boring, will mercilessly mock any corporate-feeling UI. They pick Full Damnation (9 circles). All Android except Maya (iPhone Safari).` },
  { label: 'playtest:houseparty8', desc: `8 people at a house party: two couples, 3 close friends, and Priya's NEW partner Alex who is meeting everyone for the first time tonight. Living room, drinks flowing. They pick Standard Descent (7 circles). CRITICAL DYNAMIC: personal/roast cards that target Alex (whom nobody knows) or that expose couple secrets in front of partners. Mixed iPhone/Android.` },
  { label: 'playtest:trio3', desc: `3 best friends since high school (minimum player count), quiet apartment hangout, maximum trust, they WANT the darkest content — they pick Full Damnation and max depth. Test hard: which of the 12 games mathematically or socially break at N=3 (vote spreads reveal who voted what; judge/performer roles leave only 2 voters; Roast Consensus with 3 people; Imposter with 3). Be rigorous about small-N math.` },
  { label: 'playtest:bar6', desc: `6 friends in their early 30s at a LOUD bar table after work. One shy player (Ana) who dreads spotlights. Mostly iPhones — Safari tab-kill and backgrounding realism required (one person keeps checking work Slack mid-round, screens lock). Ambient noise makes stage-phone audio inaudible. They pick Quick Dip (5 circles) because dinner comes at some point.` },
  { label: 'playtest:birthday13', desc: `Rowdy 10-person birthday party plus 3 latecomers arriving mid-game (test the Imp/audience flow). Nobody reads instructions, ever. Two people wander off to the kitchen mid-round. Short attention spans, loud, chaotic. They pick Standard Descent. Test the 3-10 player cap, vote math at N=10, latecomer conversion, and whether reveals stay a shared moment at this scale.` },
  { label: 'playtest:internetfriends5', desc: `5 internet friends (Discord server) meeting IRL for the FIRST time. They know each other's online personas deeply but zero IRL habits. Extremely internet-native, high banter skill. Test which games require IRL familiarity they don't have (Hot Seat Imposter, Over/Under receipts, Roast Consensus accuracy) vs which flourish. They pick Standard Descent.` },
]

const attackers = [
  { label: 'attack:pacing', prompt: `${COMMON}
You are a pacing auditor enforcing the Jack Principles (no dead air ever, one task at a time, game advances without stragglers). Walk EACH of the 12 games in the spec phase-by-phase with a stopwatch model at N=6 players: for every second of a round, list what each player's phone shows and what each human is doing. Find: dead-air windows (any player with nothing to do and nobody performing), sequential bottlenecks, phases where reading/typing on phones pulls heads DOWN during someone's performance, explainer overhead, transition overhead, and total Night duration vs the claimed 20/30/40 min for 5/7/9 circles (show your arithmetic; if the claim is off by >25% that is a MAJOR finding). Report kill_shots with fixes.` },
  { label: 'attack:social', prompt: `${COMMON}
You are a social-dynamics attacker (party host of 15 years, has watched game nights die). Find where this design produces ACTUAL harm or ACTUAL awkward-bad (not fun-awkward): the new-to-group stranger targeted by personal cards; couples exposed in front of partners; the shy player under spotlight rotation; Reality Check ego-gap reveals cutting too deep; spice-5 finale forced by depth mechanics on a group that chose depth while sober-optimistic; Brimstone token social cost (does burning a veto out yourself as the sensitive one? is 'anonymous' veto actually anonymous at N=3?); roast fatigue (every game is roast-shaped — does a full Night feel like being hunted?). ALSO attack the inverse: find every place a safety mechanism or design choice makes the game WHOLESOME or corporate (identity violation — the game must stay unhinged). Report kill_shots with fixes.` },
  { label: 'attack:technical', prompt: `${COMMON}
You are a technical-reality attacker (shipped realtime mobile games). Attack: (1) synced 3-2-1 reveals across N phones on bar wifi/LTE — achievable skew? does a 300ms skew murder the moment? (2) host-phone-as-Stage contradiction: it plays room audio and sits face-up mid-table while the HOST is also a player who needs private votes/secret info on that same phone — walk a Roast Consensus round and a Taboo round and find the contradiction; (3) iOS Safari: screen lock during a 60s write phase, tab backgrounding when someone checks Slack, wake-lock reliability, keyboard covering the timer during writes; (4) Cloudflare DO free tier math at 8 players x 40 min x message rates (show arithmetic vs 100k req/day and 20:1 WS message billing); (5) reconnect/rejoin flows and host-death restore — what state can actually be restored; (6) QR join in a dark bar; (7) latency on vote tallies vs auto-advance timers. Read ${SCRATCH}/report_research_browser-vs-app.md first. Report kill_shots with fixes.` },
  { label: 'attack:business', prompt: `${COMMON}
You are a business attacker (mobile games P&L operator). Read ${SCRATCH}/report_research_pricing-model.md and report_research_phone-party-games.md first. Attack: (1) HOST MUST OWN AN ANDROID — in US friend groups skewing iPhone (60%+ of under-35s), what fraction of groups contain zero willing Android host? Is Android-first a funnel killer, and what is the cheapest credible mitigation (web host? later iOS host?) — quantify; (2) first-night-free → $9.99 conversion: who actually pays, when, and does the moment-of-purchase land mid-party (friction) or after (forgotten)?; (3) differentiation: why does a group pick this over Death by AI (free, browser, AI-novelty) or Jackbox-on-a-laptop — is 'no TV needed + about YOUR friends + descent structure' a real wedge or a feature list?; (4) the name/brand positioning vs the crowded 'party deck' space; (5) solo-dev content treadmill: 12 games x cards — is the corpus size sustainable vs CAH/Jackbox writer-room reality; (6) COPPA/rating: spice-5 content + browser joiners with no age gate. Report kill_shots with fixes.` },
]

const playtestPrompt = (g) => `${COMMON}
You are running a brutally honest SIMULATED PLAYTEST. The group: ${g.desc}
Simulate the ENTIRE Night minute-by-minute as a realistic transcript in your head (do not output the full transcript): every circle, what each phone shows, what each human says/does, where laughs actually happen (be skeptical — a laugh requires a genuinely funny stimulus, not the design hoping for one), where someone is confused, bored, hurt, or checks Instagram. Use the real per-game rules from ${SCRATCH}/report_read_rules-interactions.md. Assume card content is GOOD (content is being rebuilt separately) — you are testing STRUCTURE: pacing, roles, reveals, spotlight, session arc, joins, phones. But DO flag where structure demands content quality it can't guarantee (e.g. a game that dies unless the card is a 10/10). Score fun honestly: laughs-per-round, heads-up time vs heads-down time, whether the reveal moments land as ROOM moments, whether the Descent arc builds, whether the ending satisfies. Report via the schema; failures need severity + concrete fix.`

const results = await parallel([
  ...groups.map(g => () => agent(playtestPrompt(g), { label: g.label, phase: 'Playtest', schema: PLAYTEST_SCHEMA })),
  ...attackers.map(a => () => agent(a.prompt, { label: a.label, phase: 'Attack', schema: ATTACK_SCHEMA })),
])

const labels = [...groups.map(g => g.label), ...attackers.map(a => a.label)]
const out = {}
results.forEach((r, i) => { out[labels[i]] = r })
const missing = labels.filter((l, i) => !results[i])
if (missing.length) log(`MISSING: ${missing.join(', ')}`)
return out

export const meta = {
  name: 'helldeck-playtest-r2',
  description: 'Adversarial attacks + edge-group re-validation on HELLDECK 2.0 spec v2',
  phases: [
    { title: 'Attack', detail: '4 adversarial specialists vs spec v2' },
    { title: 'Revalidate', detail: '3 edge groups replay a full Night on spec v2' },
  ],
}

const SPEC = '/private/tmp/claude-501/-Users-nicholastoledo-Development-active-HELLDECK/4eb51e65-3e38-49e9-b745-6d128c919d2d/scratchpad/spec_v2.md'
const SCRATCH = '/private/tmp/claude-501/-Users-nicholastoledo-Development-active-HELLDECK/4eb51e65-3e38-49e9-b745-6d128c919d2d/scratchpad'

const PLAYTEST_SCHEMA = {
  type: 'object',
  properties: {
    group_verdict: { type: 'string', enum: ['FUN', 'MIXED', 'NOT_FUN'] },
    fun_score_1_10: { type: 'number' },
