      note: { type: 'string' } }, required: ['game', 'verdict', 'note'] } },
    would_play_again: { type: 'boolean' },
    would_someone_pay_to_host: { type: 'boolean' },
    narrative_highlights: { type: 'string', description: 'max 400 words' },
  },
