python3 << 'EOF'
import json, glob
base = '/private/tmp/claude-501/-Users-nicholastoledo-Development-active-HELLDECK/4eb51e65-3e38-49e9-b745-6d128c919d2d/scratchpad'
out = {}
for fn in sorted(glob.glob(f'{base}/autopsy_deck_*.json')):
    game = fn.split('autopsy_deck_')[-1].replace('.json','')
    with open(fn) as f: d = json.load(f)
    out[game] = {'reqs': d['rebuild_requirements'], 'keeps': d['keep_ids'],
                 'model_cards': [e for e in d['examples'] if e['verdict']=='KEEP']}
with open(f'{base}/rebuild_inputs.json','w') as f: json.dump(out, f, indent=1)
for g, v in out.items():
    print(f"\n### {g} ({len(v['keeps'])} keeps)")
    for r in v['reqs']: print(f"  REQ: {r[:260]}")
EOF

