export const meta = {
  name: 'helldeck-rebuild-wave1',
  description: 'Rebuild the four 150-card launch decks: write -> curate -> adversarially verify',
  phases: [
    { title: 'Write', detail: '3 register-assigned writers per deck' },
    { title: 'Curate', detail: 'merge, dedup skeletons, enforce quotas, rank to 165' },
    { title: 'Verify', detail: '2 adversarial screeners per deck' },
  ],
}

const REPO = '/Users/nicholastoledo/Development/active/HELLDECK'
const S = '/private/tmp/claude-501/-Users-nicholastoledo-Development-active-HELLDECK/4eb51e65-3e38-49e9-b745-6d128c919d2d/scratchpad'

const CARD = { type: 'object', properties: {
  text: { type: 'string' }, exposure: { type: 'number' }, chaos: { type: 'number' },
  register: { type: 'string' }, skeleton: { type: 'string', description: 'short slug of the structural shape, for dedup' },
  extra: { type: 'object', description: 'per-deck structured fields' } },
  required: ['text', 'exposure', 'chaos', 'register', 'skeleton'] }

const WRITER_SCHEMA = { type: 'object', properties: { cards: { type: 'array', items: CARD } }, required: ['cards'] }
const CURATOR_SCHEMA = { type: 'object', properties: { gold: { type: 'array', items: CARD }, notes: { type: 'string' } }, required: ['gold'] }
const VERIFY_SCHEMA = { type: 'object', properties: { fails: { type: 'array', items: { type: 'object', properties: {
  text: { type: 'string' }, law: { type: 'string' }, why: { type: 'string' } }, required: ['text', 'law', 'why'] } } }, required: ['fails'] }

const DECKS = [
  { key: 'roast_consensus', name: 'ROAST CONSENSUS', target: 165,
    mech: "Everyone secretly votes which PRESENT player fits the prompt; name-in-lights reveal; table roasts. 'Who would...' / 'Who has...' forms. extra: {} (none).",
    fields: 'No extra fields.' },
  { key: 'fill_in_finisher', name: 'FILL-IN FINISHER', target: 165,
    mech: "Setup with one blank _____; everyone writes a punchline; a Reader performs all answers ALOUD in a chosen tone; room votes. Cards are SETUPS ONLY.",
    fields: "extra: {} (none). The blank is written as _____ in text." },
  { key: 'over_under', name: 'OVER/UNDER', target: 165,
    mech: "Stat about a named subject; room debates the line ALOUD; secret bets; subject reveals truth via phone receipt. ≥70% must be phone-receipt-resolvable in <10s.",
    fields: "extra: {receipt_surface: string ('Settings>Screen Time' / 'Photos search' / 'spoken claim' etc.), timebox: string ('today'/'this week'/'this month'/'right now'/'lifetime-bounded-event')}." },
  { key: 'confession_or_cap', name: 'CONFESSION OR CAP', target: 165,
    mech: "Confessor dealt 3, picks 1, locks TRUE/FALSE, performs the story aloud; jury votes believe/cap. First-person 'I once...' claims, lockable TRUE by ANYONE at the table.",
    fields: 'No extra fields.' },
]

const REGISTER_SPLITS = [
  "REGISTER ASSIGNMENT: ~40% absurdist/escalation, ~30% petty-domestic (roommates, thermostats, dishes, neighbors, family), ~30% relatable-observational (your ONLY allocation of it — make it scene-specific, never vibe-verdict).",
  "REGISTER ASSIGNMENT: ~35% deadpan understatement + sustained menace, ~35% gross-out/body + physical, ~30% high-register parody voices (legalese, nature-documentary, noir, corporate-memo, true-crime narrator — the VOICE is the frame, content stays HELLDECK).",
  "REGISTER ASSIGNMENT: ~40% table-aware/room-referencing (the {NAME}/'in this room' lane — could only exist in a game played by these people; respect the third-party firewall), ~30% reference-worlds-beyond-phones (food, animals, myth, small-town, trades, sports, medicine, nature), ~30% euphemism-engine cards (self-incriminating reframes that open loops).",
]

const writerPrompt = (d, split, idx) => `You are one of three comedy writers rebuilding the ${d.name} deck for HELLDECK 2.0 — a phones-only party game (every player on own phone, same room). The old deck was autopsied: ~86% failed. You write the replacement.

READ FIRST (Read tool, all three):
1. ${REPO}/CONTENT_BIBLE.md — THE LAW. Every card must satisfy the Ten Commandments, the two-axis E/C rating, and this deck's per-deck laws.
2. ${S}/autopsy_deck_${d.key}.json — this deck's autopsy: rebuild requirements (binding detail), model cards (calibration for what KEEP-grade means), keep_ids.
3. ${S}/corpus/${d.key}.md — the OLD deck. Never duplicate an old joke or skeleton. Old REWRITE-tier premises may be harvested ONLY if transformed per the bible.

GAME MECHANIC: ${d.mech}
STRUCTURED FIELDS: ${d.fields}
${split}

WRITE ~85 CANDIDATE CARDS, then SELF-CULL to your best 60 (kill your bottom third — if you can't name why a card survives, it doesn't). Output exactly your surviving cards via the schema. Every card: text (speakable in one breath), exposure 1-5 and chaos 1-5 honestly rated (chaos ≥3 ALWAYS — no wholesome tier exists), register tag, skeleton slug (for dedup — be honest and specific, e.g. 'banned-from-venue', 'euphemism-reframe', 'receipt-count'). Spread exposure across tiers: roughly 15% E1, 20% E2, 30% E3, 20% E4, 15% E5 — the game needs a full descent curve. Writer #${idx + 1} of 3.`

const curatorPrompt = (d, merged) => `You are the deck curator for ${d.name} in the HELLDECK 2.0 rebuild. Read ${REPO}/CONTENT_BIBLE.md (the law) and ${S}/autopsy_deck_${d.key}.json (requirements + keep_ids + model cards). Also read the OLD deck ${S}/corpus/${d.key}.md so keepers aren't duplicated by new cards.

Below are ${merged.length} candidate cards from 3 writers (JSON). Curate to the ${d.target} best:
1. DEDUP: skeleton budget max 2 per skeleton slug (also catch same-shape cards whose slugs differ — judge the actual structure); kill near-duplicate premises.
2. QUOTAS: ≤35% relatable-observational register; ≤20% phone/app references; exposure spread ~15/20/30/20/15 across E1-E5; chaos ≥3 everywhere.
3. MECHANIC GATE per the deck laws (two-victim test / 3-answers / receipt-resolvable+timebox / plausibility-window as applicable).
4. QUALITY RANK: model cards in the autopsy JSON define the bar (CONTEXTUAL minimum, DISTINCTIVE target). Kill anything below.
Fix small defects yourself (tighten wording to one breath, correct E/C ratings, fill missing extra fields) rather than killing an otherwise-great card. Return exactly ${d.target} gold cards (or fewer ONLY if candidates genuinely run out above the bar), ranked best-first.

CANDIDATES:
${JSON.stringify(merged)}`

const verifierPrompt = (d, cards, lens) => `You are an adversarial content screener for the rebuilt ${d.name} deck (HELLDECK 2.0). Read ${REPO}/CONTENT_BIBLE.md first. Your lens: ${lens}. Below are curated GOLD candidates. Your job is to FAIL cards, not to like them — a shipped bad card costs a real table's night. For each failing card output its exact text, the law broken, and why. Judge silently-read-vs-aloud, shelf-life, firewall, wholesome-test, specificity-test, mechanic fit, E/C honesty. Do NOT fail cards for taste alone if they pass the laws — edgy-but-lawful is the brand. Cards:
${JSON.stringify(cards)}`

const results = await pipeline(
  DECKS,
  (d) => parallel(REGISTER_SPLITS.map((split, i) => () =>
    agent(writerPrompt(d, split, i), { label: `write:${d.key}:${i + 1}`, phase: 'Write', schema: WRITER_SCHEMA })
  )).then(ws => ({ d, merged: ws.filter(Boolean).flatMap(w => w.cards) })),
  ({ d, merged }) => agent(curatorPrompt(d, merged), { label: `curate:${d.key}`, phase: 'Curate', schema: CURATOR_SCHEMA })
    .then(c => ({ d, gold: c.gold, notes: c.notes })),
  ({ d, gold, notes }) => parallel([
    () => agent(verifierPrompt(d, gold.slice(0, Math.ceil(gold.length / 2)), 'laws 1-5: scene-not-verdict, card-asks-room-answers, contest tests, E/C honesty, third-party firewall'), { label: `verify:${d.key}:a`, phase: 'Verify', schema: VERIFY_SCHEMA }),
    () => agent(verifierPrompt(d, gold.slice(Math.ceil(gold.length / 2)), 'laws 6-10: shelf-life vocabulary, skeleton duplication, table-aware quota integrity, spoken-not-silent, register quotas + wholesome test'), { label: `verify:${d.key}:b`, phase: 'Verify', schema: VERIFY_SCHEMA }),
  ]).then(vs => {
    const failTexts = new Set(vs.filter(Boolean).flatMap(v => v.fails).map(f => f.text))
    const shipped = gold.filter(c => !failTexts.has(c.text))
    return { deck: d.key, shipped, dropped: gold.length - shipped.length, curator_notes: notes || '', fail_reasons: vs.filter(Boolean).flatMap(v => v.fails).map(f => `${f.law}: ${f.text.slice(0, 60)}`) }
  })
)

const out = {}
for (const r of results.filter(Boolean)) {
  out[r.deck] = { count: r.shipped.length, dropped: r.dropped, fail_reasons: r.fail_reasons.slice(0, 25) }
  log(`${r.deck}: shipped ${r.shipped.length}, verifier-dropped ${r.dropped}`)
}
return { summary: out, decks: Object.fromEntries(results.filter(Boolean).map(r => [r.deck, r.shipped])) }

