// The one function. Pure, deterministic given (state, event, seed).
// DESCENT_BUILD_SPEC.md Part 2.1 + Part 4. Implementation tasks: D-111, D-115, D-124..D-126.
import type { GameEvent, ReduceResult, RoomState } from './types.js';
import { rng } from './rng.js';

export function initialRoom(code: string, createdAt: number, entitled: boolean): RoomState {
  return {
    code,
    createdAt,
    config: null,
    players: [],
    phase: { k: 'LOBBY' },
    arc: [],
    circleIdx: 0,
    gameState: null,
    usedCardIds: [],
    usedSkeletons: {},
    devilsBargain: null,
    epoch: 0,
    entitled,
    telemetry: [],
  };
}

export function reduce(s: RoomState, e: GameEvent, seed: string): ReduceResult {
  const rand = rng(`${seed}:${s.epoch}:${e.t}`);
  switch (e.t) {
    case 'JOIN':
      return handleJoin(s, e);
    // D-111: CONFIG, CEILING, ATTEST18, BEGIN → CONSENT → arc build → CIRCLE_INTRO chain
    // D-115: BURN handling inside DEAL ceremony; blocking terminals (VOID_ROUND, PLEAD_FIFTH, TIMER)
    // D-116: DESCEND / FIRE / REVEAL holds / LADDER / JUDGMENT
    // Per-game INPUT dispatch → games/<deck>.ts (D-112, D-121..D-123, D-131..D-133)
    default:
      return { state: s, effects: [] };
  }
  void rand;
}

function handleJoin(s: RoomState, e: Extract<GameEvent, { t: 'JOIN' }>): ReduceResult {
  if (s.players.some((p) => p.id === e.id)) {
    // reconnect-as-join: mark connected
    const players = s.players.map((p) => (p.id === e.id ? { ...p, connected: true, lastSeenAt: e.at } : p));
    return { state: { ...s, players }, effects: [{ k: 'BROADCAST' }] };
  }
  const activeCount = s.players.filter((p) => p.role !== 'imp').length;
  const joinsAsImp = s.phase.k !== 'LOBBY' || activeCount >= 12;
  const name = uniqueName(e.name, s.players.map((p) => p.name));
  const player = {
    id: e.id,
    name,
    avatar: e.avatar,
    role: (s.players.length === 0 ? 'host' : joinsAsImp ? 'imp' : 'player') as 'host' | 'player' | 'imp',
    seat: s.players.length,
    connected: true,
    lastSeenAt: e.at,
    heatCeiling: 3 as const,
    attested18: false,
    brimstones: 2,
    score: 0,
    spotlightCount: 0,
    freshMeat: true,
  };
  return {
    state: { ...s, players: [...s.players, player] },
    effects: [{ k: 'BROADCAST' }, { k: 'SNAPSHOT' }],
  };
}

export function uniqueName(raw: string, existing: string[]): string {
  const base = raw.trim().toUpperCase().slice(0, 14) || 'SINNER';
  if (!existing.includes(base)) return base;
  for (let i = 2; ; i++) {
    const candidate = `${base} (${i})`;
    if (!existing.includes(candidate)) return candidate;
  }
}

