// RoomDO: the authoritative room. WS hub (hibernation API), Alarm timers, SQLite snapshots.
// DESCENT_BUILD_SPEC.md Part 3 (protocol), Part 4 (engine wiring). Tasks D-103, D-104, D-113.
import { initialRoom, reduce, type Effect, type GameEvent, type RoomState } from '@helldeck/engine';
import { redactFor } from './redact.js';

interface Attachment {
  playerId: string;
  clockOffset: number; // server - client, median of pings
}

export class RoomDO implements DurableObject {
  private state: RoomState | null = null;
  private timers = new Map<string, number>(); // timerId -> atMs (persisted; nearest drives the Alarm)

  constructor(
    private ctx: DurableObjectState,
    private env: unknown,
  ) {}

  private async load(): Promise<void> {
    if (this.state) return;
    this.state = ((await this.ctx.storage.get('room')) as RoomState | undefined) ?? null;
    this.timers = new Map(Object.entries(((await this.ctx.storage.get('timers')) as Record<string, number>) ?? {}));
  }

  async fetch(req: Request): Promise<Response> {
    await this.load();
    const url = new URL(req.url);

    if (req.method === 'POST' && url.pathname === '/init') {
      const code = url.searchParams.get('code') ?? 'XXXX';
      if (!this.state) {
        this.state = initialRoom(code, Date.now(), true /* entitlement checked at BEGIN, D-412 */);
        await this.persist();
      }
      return new Response('ok');
    }

    if (req.headers.get('Upgrade') === 'websocket') {
      if (!this.state) return new Response('NO SUCH PIT', { status: 404 });
      const pair = new WebSocketPair();
      const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
      // Hibernation API: survives DO eviction; heartbeats via auto-response (D-103).
      this.ctx.acceptWebSocket(server);
      // JOIN/reseat handled on first client message (token in query — D-105 wires it).
      server.serializeAttachment({ playerId: url.searchParams.get('token') ?? '', clockOffset: 0 } satisfies Attachment);
      return new Response(null, { status: 101, webSocket: client });
    }

    return new Response('bad request', { status: 400 });
  }

  async webSocketMessage(ws: WebSocket, raw: string | ArrayBuffer): Promise<void> {
    await this.load();
    if (!this.state || typeof raw !== 'string') return;
    let msg: { t: string; [k: string]: unknown };
    try {
      msg = JSON.parse(raw);
    } catch {
      return;
    }
    // D-104: PONG -> clock offset sampling lives here.
    // Map wire msg -> GameEvent (Part 3.2 table). Unknown -> ERR BAD_INPUT.
    const event = this.toEvent(ws, msg);
    if (event) await this.dispatch(event);
  }

  async webSocketClose(ws: WebSocket): Promise<void> {
    await this.load();
    const att = ws.deserializeAttachment() as Attachment | null;
    if (att?.playerId) await this.dispatch({ t: 'LEAVE', id: att.playerId, at: Date.now() });
  }

  async alarm(): Promise<void> {
    await this.load();
    const now = Date.now();
    for (const [timerId, atMs] of [...this.timers]) {
      if (atMs <= now) {
        this.timers.delete(timerId);
        await this.dispatch({ t: 'TIMER', timerId, at: now });
      }
    }
    await this.armAlarm();
  }

  // ===== engine wiring =====
  private async dispatch(event: GameEvent): Promise<void> {
    if (!this.state) return;
    const { state, effects } = reduce(this.state, event, this.state.code);
    this.state = state;
    await this.runEffects(effects);
  }

  private async runEffects(effects: Effect[]): Promise<void> {
    for (const ef of effects) {
      switch (ef.k) {
        case 'SCHEDULE':
          this.timers.set(ef.timerId, ef.atMs);
          await this.armAlarm();
          break;
        case 'CANCEL':
          this.timers.delete(ef.timerId);
          break;
        case 'BROADCAST':
          this.broadcast();
          break;
        case 'SEND':
          this.sendPrivate(ef.to, ef.kind, ef.payload);
          break;
        case 'SNAPSHOT':
          await this.persist();
          break;
        case 'AUDIO':
          this.broadcastRaw({ t: 'AUDIO', sting: ef.sting });
          break;
      }
    }
  }

  private broadcast(): void {
    if (!this.state) return;
    for (const ws of this.ctx.getWebSockets()) {
      const att = ws.deserializeAttachment() as Attachment | null;
      const view = redactFor(this.state, att?.playerId ?? '');
      try {
        ws.send(JSON.stringify({ t: 'STATE', s: view, epoch: this.state.epoch }));
      } catch {
        /* dead socket; close event will handle */
      }
    }
  }

