import { useState } from 'preact/hooks';

function App() {
  const path = location.pathname.slice(1).toUpperCase();
  const isCode = /^[BCDFGHJKLMNPRSTVWXYZ]{4}$/.test(path);
  return isCode ? <JoinScreen code={path} /> : <Landing />;
}

function Landing() {
  const [code, setCode] = useState('');
  return (
    <main style="flex:1;display:flex;flex-direction:column;justify-content:center;padding:24px;gap:16px">
      <h1 style="font-size:15vw;letter-spacing:-0.04em;color:var(--bone)">
        HELL<span style="color:var(--ember)">DECK</span>
      </h1>
      <button
        style="padding:20px;font-size:20px;font-weight:800;background:var(--blood);color:var(--bone);border:none"
        onClick={async () => {
          const r = await fetch('/api/room', { method: 'POST' });
          const { code } = (await r.json()) as { code: string };
          location.href = `/${code}`;
        }}
      >
        START A NIGHT
      </button>
      <div style="display:flex;gap:8px">
        <input
          style="flex:1;padding:16px;font-size:24px;letter-spacing:0.5em;text-transform:uppercase;background:#161314;color:var(--bone);border:1px solid var(--ash)"
          maxLength={4}
          placeholder="CODE"
          value={code}
          onInput={(e) => setCode((e.target as HTMLInputElement).value)}
        />
        <button
          style="padding:16px 20px;font-weight:800;background:transparent;color:var(--ember);border:1px solid var(--ember)"
          onClick={() => (location.href = `/${code.toUpperCase()}`)}
        >
          JOIN
        </button>
      </div>
      <p style="color:var(--ash);font-size:12px">18+. Play with people who can take it.</p>
    </main>
  );
}

function JoinScreen({ code }: { code: string }) {
  // D-105: name + avatar + attest -> connect() from net/ws.ts -> lobby render from STATE.
  return (
    <main style="flex:1;display:flex;align-items:center;justify-content:center">
      <h2>
        ROOM <span style="color:var(--ember)">{code}</span> — join flow lands in D-105
      </h2>
    </main>
  );
}

render(<App />, document.getElementById('app')!);

