    this.ws = new WebSocket(`${proto}://${location.host}/ws/${this.code}?token=${this.token}&v=1`);
    this.ws.onopen = () => (this.backoff = 500);
    this.ws.onclose = () => {
      if (!this.closed) {
        setTimeout(() => this.connect(), this.backoff);
        this.backoff = Math.min(this.backoff * 2, 8000);
      }
    };
    this.ws.onmessage = (ev) => this.route(JSON.parse(ev.data as string));
  }

  send(msg: Record<string, unknown>): void {
    if (this.ws?.readyState === WebSocket.OPEN) this.ws.send(JSON.stringify(msg));
  }

  serverNow(): number {
    return Date.now() + this.offset;
  }

  private route(m: { t: string; [k: string]: unknown }): void {
    switch (m.t) {
      case 'STATE': {
        const epoch = Number(m['epoch']);
        if (epoch <= this.epoch) return; // stale
        this.epoch = epoch;
        this.h.onState(m['s'], epoch);
        break;
      }
      case 'PRIVATE':
        this.h.onPrivate(String(m['k']), m['p']);
        break;
      case 'PING':
        this.send({ t: 'PONG', id: m['id'], cl: Date.now() });
        break;
      case 'AT':
        this.h.onDeadline(String(m['timerId']), Number(m['at']));
        break;
      case 'AUDIO':
        this.h.onAudio(String(m['sting']));
        break;
      case 'HEAT':
        this.h.onHeat(Number(m['n']));
        break;
    }
  }
}

