48	// state-level `viewFor(state, viewerId)` that routes to the active GameModule.view().
49	// Resolved dynamically so this package compiles before AND after that lands; until then
50	// gameView is null — the redaction-safe default (null leaks nothing).
51	type GameViewFn = (s: RoomState, viewerId: string) => unknown;
52	let resolvedView: GameViewFn | null | undefined;
53	function grab(ns: Record<string, unknown>, key: string): unknown {
54	  try {
55	    return ns[key]; // namespace proxies (e.g. vitest mocks) may throw on missing exports
56	  } catch {
57	    return undefined;
58	  }
