62	  const ns = Engine as unknown as Record<string, unknown>;
63	  const candidate = grab(ns, 'viewFor') ?? grab(ns, 'gameViewFor') ?? grab(ns, 'gameView');
64	  resolvedView = typeof candidate === 'function' ? (candidate as GameViewFn) : null;
