91	  const rand = rng(`${seed}:${s.epoch}:${e.t}`);
92	  switch (e.t) {
93	    case 'JOIN':
94	      return handleJoin(s, e);
95	    case 'LEAVE':
96	      return handleLeave(s, e);
97	    case 'RECONNECT':
98	      return handleReconnect(s, e);
99	    case 'ATTEST18':
100	      return handleAttest(s, e);
101	    case 'CONFIG':
102	      return handleConfig(s, e);
103	    case 'CEILING':
104	      return handleCeiling(s, e);
105	    case 'BEGIN':
106	      return handleBegin(s, e, seed);
107	    case 'TIMER':
108	      return handleTimer(s, e, rand);
109	    case 'INPUT':
110	      return routeModule(s, e.at, rand, (m, ctx) => m.input(ctx, e.id, e.payload));
111	    case 'BURN':
112	      return handleBurn(s, e);
113	    case 'DESCEND':
114	      return handleDescend(s, e, rand);
115	    case 'FIRE':
116	      return handleFire(s, e);
117	    case 'PLEAD_FIFTH':
118	      return routeControl(s, e.id, 'FIFTH', e.at, rand);
119	    case 'VOID_ROUND':
120	      return isHost(s, e.id) ? routeControl(s, e.id, 'VOID', e.at, rand) : noop(s);
121	    case 'SKIP_EM':
122	      return routeControl(s, e.id, 'SKIPEM', e.at, rand);
123	    case 'REST_CASE':
124	      return routeControl(s, e.id, 'REST', e.at, rand);
125	    default:
126	      return noop(s);
