    return verifyStage(d, gold, notes)
  },
)

async function verifyStage(d, gold, notes) {
  return parallel([
    () => agent(verifierPrompt(d, gold.slice(0, Math.ceil(gold.length / 2)), 'laws 1-5: scene-not-verdict, card-asks-room-answers, contest tests, E/C honesty, third-party firewall'), { label: `verify:${d.key}:a`, phase: 'Verify', schema: VERIFY_SCHEMA }),
    () => agent(verifierPrompt(d, gold.slice(Math.ceil(gold.length / 2)), 'laws 6-10: shelf-life vocabulary, skeleton duplication, table-aware quota integrity, spoken-not-silent, register quotas + wholesome test'), { label: `verify:${d.key}:b`, phase: 'Verify', schema: VERIFY_SCHEMA }),
  ]).then(vs => {
    const failTexts = new Set(vs.filter(Boolean).flatMap(v => v.fails).map(f => f.text))
    const shipped = gold.filter(c => !failTexts.has(c.text))
    return { deck: d.key, shipped, dropped: gold.length - shipped.length, curator_notes: notes || '', fail_reasons: vs.filter(Boolean).flatMap(v => v.fails).map(f => `${f.law}: ${f.text.slice(0, 60)}`) }
  })
)

const out = {}
for (const r of results.filter(Boolean)) {
